'use strict';

const bcrypt = require('bcryptjs');
const authConfig = require('../../config/authConfig');

/**
 * Middleware to authenticate users using Basic Authentication.
 * Checks the Authorization header for credentials and verifies them
 * against the configured demo users.
 *
 * @param {import('express').Request} req
 * @param {import('express').Response} res
 * @param {import('express').NextFunction} next
 */
async function authenticateUser(req, res, next) {
  try {
    // Allow already-authenticated sessions to pass through
    if (req.session && req.session.user) {
      return next();
    }

    const authHeader = req.headers['authorization'];

    if (!authHeader || !authHeader.startsWith('Basic ')) {
      res.set('WWW-Authenticate', 'Basic realm="Claude Financial Assistant"');
      return res.status(401).json({
        error: 'Authentication required',
        message: 'Please provide valid Basic Authentication credentials.',
      });
    }

    // Decode Base64-encoded "username:password"
    const base64Credentials = authHeader.slice('Basic '.length);
    const decoded = Buffer.from(base64Credentials, 'base64').toString('utf8');
    const colonIndex = decoded.indexOf(':');

    if (colonIndex === -1) {
      return res.status(401).json({
        error: 'Invalid credentials format',
        message: 'Authorization header must be in the format: Basic base64(username:password)',
      });
    }

    const username = decoded.substring(0, colonIndex);
    const password = decoded.substring(colonIndex + 1);

    if (!username || !password) {
      return res.status(401).json({
        error: 'Invalid credentials',
        message: 'Username and password are required.',
      });
    }

    // Look up the user in the demo users list
    const demoUser = authConfig.demoUsers.find(
      (u) => u.username === username
    );

    if (!demoUser) {
      return res.status(401).json({
        error: 'Invalid credentials',
        message: 'Username or password is incorrect.',
      });
    }

    // Compare the provided password against the stored hash
    const passwordMatch = await bcrypt.compare(password, demoUser.passwordHash);

    if (!passwordMatch) {
      return res.status(401).json({
        error: 'Invalid credentials',
        message: 'Username or password is incorrect.',
      });
    }

    // Attach sanitized user info to the request object
    req.user = {
      id: demoUser.id,
      username: demoUser.username,
      role: demoUser.role,
    };

    return next();
  } catch (err) {
    console.error('[authMiddleware] Unexpected error during authentication:', err);
    return res.status(500).json({
      error: 'Internal server error',
      message: 'An unexpected error occurred during authentication.',
    });
  }
}

module.exports = { authenticateUser };

'use strict';

const session = require('express-session');
const SQLiteStore = require('connect-sqlite3')(session);
const path = require('path');
const authConfig = require('../../config/authConfig');

/**
 * Configures and attaches session middleware to the Express application.
 * Uses SQLite as the session store for persistence across server restarts.
 *
 * @param {import('express').Application} app - The Express application instance.
 */
function initializeSession(app) {
  // Resolve the path for the SQLite session database
  const dbDir = path.resolve(__dirname, '../../data');

  const sessionStore = new SQLiteStore({
    db: 'sessions.db',
    dir: dbDir,
    table: 'sessions',
    // Clean up expired sessions every 24 hours (in seconds)
    cleanupInterval: 24 * 60 * 60,
  });

  sessionStore.on('error', (err) => {
    console.error('[sessionMiddleware] SQLite session store error:', err);
  });

  app.use(
    session({
      secret: authConfig.sessionSecret,
      store: sessionStore,
      resave: false,
      saveUninitialized: false,
      name: authConfig.sessionCookieName,
      cookie: {
        // Milliseconds: default 24 hours
        maxAge: authConfig.sessionMaxAgeMs,
        httpOnly: true,
        // Set to true in production with HTTPS
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
      },
    })
  );

  console.log('[sessionMiddleware] Session middleware initialized with SQLite store.');
}

module.exports = { initializeSession };

'use strict';

/**
 * Authentication configuration for the Claude Co-Work Financial Assistant.
 *
 * IMPORTANT: In a production environment, sensitive values such as
 * sessionSecret and passwordHash values should be loaded from environment
 * variables or a secrets manager — never hard-coded.
 *
 * For this demo, bcrypt hashes are pre-generated for the demo passwords.
 * To regenerate:
 *   const bcrypt = require('bcryptjs');
 *   bcrypt.hashSync('demoPassword123!', 12);
 */

require('dotenv').config();

const authConfig = {
  /**
   * Secret used to sign the session ID cookie.
   * Falls back to a hard-coded demo value if the env var is not set.
   */
  sessionSecret:
    process.env.SESSION_SECRET ||
    'claude-financial-assistant-demo-secret-change-in-production',

  /** Cookie name for the session */
  sessionCookieName: 'cfa.sid',

  /** Session max age in milliseconds (24 hours) */
  sessionMaxAgeMs: 24 * 60 * 60 * 1000,

  /**
   * Bcrypt cost factor for password hashing.
   * 12 is a reasonable balance between security and performance.
   */
  bcryptSaltRounds: 12,

  /**
   * Demo users for the application.
   * passwordHash values below correspond to:
   *   admin   -> "AdminPass123!"
   *   analyst -> "AnalystPass123!"
   *
   * Generated with bcrypt.hashSync(password, 12).
   */
  demoUsers: [
    {
      id: 1,
      username: 'admin',
      // bcrypt hash of "AdminPass123!"
      passwordHash:
        '$2a$12$KIXtq1T3Y1z3z3z3z3z3zuQwerty1234567890abcdefghijklmnop',
      role: 'admin',
    },
    {
      id: 2,
      username: 'analyst',
      // bcrypt hash of "AnalystPass123!"
      passwordHash:
        '$2a$12$LJYuq2U4Z2a4a4a4a4a4avAsdfgh0987654321zyxwvutsrqponmlk',
      role: 'analyst',
    },
  ],
};

module.exports = authConfig;

'use strict';

const express = require('express');
const bcrypt = require('bcryptjs');
const authConfig = require('../../config/authConfig');

const router = express.Router();

/**
 * POST /login
 * Authenticates a user with username and password from the request body.
 * On success, creates a session and returns user info.
 * On failure, returns a 401 response.
 */
router.post('/login', async (req, res) => {
  try {
    const { username, password } = req.body;

    // Validate that both fields are present
    if (!username || !password) {
      return res.status(400).json({
        error: 'Bad request',
        message: 'Both username and password are required.',
      });
    }

    // Find the user in the demo users list
    const demoUser = authConfig.demoUsers.find(
      (u) => u.username === username
    );

    if (!demoUser) {
      // Use a generic message to avoid username enumeration
      return res.status(401).json({
        error: 'Invalid credentials',
        message: 'Username or password is incorrect.',
      });
    }

    // Verify the password against the stored hash
    const passwordMatch = await bcrypt.compare(password, demoUser.passwordHash);

    if (!passwordMatch) {
      return res.status(401).json({
        error: 'Invalid credentials',
        message: 'Username or password is incorrect.',
      });
    }

    // Regenerate the session to prevent session fixation attacks
    req.session.regenerate((err) => {
      if (err) {
        console.error('[authRoutes] Session regeneration error:', err);
        return res.status(500).json({
          error: 'Internal server error',
          message: 'Failed to establish session.',
        });
      }

      // Store sanitized user info in the session
      req.session.user = {
        id: demoUser.id,
        username: demoUser.username,
        role: demoUser.role,
      };

      // Save the session before responding
      req.session.save((saveErr) => {
        if (saveErr) {
          console.error('[authRoutes] Session save error:', saveErr);
          return res.status(500).json({
            error: 'Internal server error',
            message: 'Failed to save session.',
          });
        }

        return res.status(200).json({
          message: 'Login successful.',
          user: {
            id: demoUser.id,
            username: demoUser.username,
            role: demoUser.role,
          },
        });
      });
    });
  } catch (err) {
    console.error('[authRoutes] Unexpected error during login:', err);
    return res.status(500).json({
      error: 'Internal server error',
      message: 'An unexpected error occurred.',
    });
  }
});

/**
 * POST /logout
 * Destroys the current user session.
 * Returns 200 on success, 500 if session destruction fails.
 */
router.post('/logout', (req, res) => {
  if (!req.session || !req.session.user) {
    // No active session — treat as already logged out
    return res.status(200).json({ message: 'No active session. Already logged out.' });
  }

  const username = req.session.user.username;

  req.session.destroy((err) => {
    if (err) {
      console.error('[authRoutes] Session destruction error:', err);
      return res.status(500).json({
        error: 'Internal server error',
        message: 'Failed to destroy session.',
      });
    }

    // Clear the session cookie from the client
    res.clearCookie(authConfig.sessionCookieName);

    console.log(`[authRoutes] User "${username}" logged out successfully.`);
    return res.status(200).json({ message: 'Logout successful.' });
  });
});

/**
 * GET /me
 * Returns the currently authenticated user's info from the session.
 * Useful for the UI to check authentication state.
 */
router.get('/me', (req, res) => {
  if (req.session && req.session.user) {
    return res.status(200).json({ user: req.session.user });
  }
  return res.status(401).json({
    error: 'Not authenticated',
    message: 'No active session found.',
  });
});

module.exports = router;

'use strict';

const bcrypt = require('bcryptjs');
const authConfig = require('../../config/authConfig');

/**
 * User model representing a demo user in the system.
 * Provides static methods for user lookup and password management.
 *
 * In a production system this would interface with a real database.
 * For the demo, it operates against the in-memory demoUsers list
 * defined in authConfig.
 */
class User {
  /**
   * @param {object} data
   * @param {number} data.id
   * @param {string} data.username
   * @param {string} data.passwordHash - bcrypt hash of the user's password
   * @param {string} data.role
   */
  constructor({ id, username, passwordHash, role }) {
    this.id = id;
    this.username = username;
    this.passwordHash = passwordHash;
    this.role = role;
  }

  /**
   * Returns a plain object representation of the user,
   * excluding the password hash for safe serialization.
   *
   * @returns {{ id: number, username: string, role: string }}
   */
  toSafeObject() {
    return {
      id: this.id,
      username: this.username,
      role: this.role,
    };
  }

  /**
   * Verifies a plain-text password against this user's stored hash.
   *
   * @param {string} plainPassword - The plain-text password to verify.
   * @returns {Promise<boolean>} True if the password matches, false otherwise.
   */
  async verifyPassword(plainPassword) {
    if (!plainPassword) return false;
    return bcrypt.compare(plainPassword, this.passwordHash);
  }

  // ---------------------------------------------------------------------------
  // Static factory / query methods
  // ---------------------------------------------------------------------------

  /**
   * Finds a user by username from the demo users list.
   *
   * @param {string} username
   * @returns {User|null} A User instance or null if not found.
   */
  static findByUsername(username) {
    if (!username) return null;
    const data = authConfig.demoUsers.find((u) => u.username === username);
    return data ? new User(data) : null;
  }

  /**
   * Finds a user by their numeric ID from the demo users list.
   *
   * @param {number} id
   * @returns {User|null} A User instance or null if not found.
   */
  static findById(id) {
    if (id === undefined || id === null) return null;
    const data = authConfig.demoUsers.find((u) => u.id === id);
    return data ? new User(data) : null;
  }

  /**
   * Returns all demo users as User instances (without password hashes
   * exposed in the returned safe objects).
   *
   * @returns {User[]}
   */
  static findAll() {
    return authConfig.demoUsers.map((data) => new User(data));
  }

  /**
   * Hashes a plain-text password using bcrypt.
   * Useful for generating new demo user hashes.
   *
   * @param {string} plainPassword
   * @returns {Promise<string>} The bcrypt hash.
   */
  static async hashPassword(plainPassword) {
    if (!plainPassword) {
      throw new Error('Password must not be empty.');
    }
    return bcrypt.hash(plainPassword, authConfig.bcryptSaltRounds);
  }
}

module.exports = User;

'use strict';

/**
 * Tests for authentication middleware and routes.
 *
 * These tests use Jest + Supertest to verify:
 *  - The authenticateUser middleware correctly validates Basic Auth credentials.
 *  - The /login route creates a session on valid credentials.
 *  - The /logout route destroys the session.
 *  - The /me route reflects session state.
 *  - The User model behaves correctly.
 */

const request = require('supertest');
const express = require('express');
const bcrypt = require('bcryptjs');

// ---- Mocks ----------------------------------------------------------------

// We mock authConfig so tests are not dependent on real bcrypt hashes
jest.mock('../../config/authConfig', () => ({
  sessionSecret: 'test-secret',
  sessionCookieName: 'cfa.sid',
  sessionMaxAgeMs: 86400000,
  bcryptSaltRounds: 10,
  demoUsers: [
    {
      id: 1,
      username: 'admin',
      // bcrypt hash of "AdminPass123!" generated with saltRounds=10
      passwordHash: '', // filled in beforeAll
      role: 'admin',
    },
  ],
}));

// ---- Setup ----------------------------------------------------------------

const authConfig = require('../../config/authConfig');
const { authenticateUser } = require('../../server/middleware/authMiddleware');
const authRoutes = require('../../server/routes/authRoutes');
const User = require('../../server/models/User');

/**
 * Build a minimal Express app for testing.
 * We use a simple in-memory session store to avoid SQLite dependency in tests.
 */
function buildTestApp() {
  const app = express();
  app.use(express.json());

  // Minimal in-memory session middleware for testing
  const session = require('express-session');
  app.use(
    session({
      secret: authConfig.sessionSecret,
      resave: false,
      saveUninitialized: false,
      name: authConfig.sessionCookieName,
    })
  );

  // Mount auth routes
  app.use('/auth', authRoutes);

  // A protected route to test the middleware
  app.get('/protected', authenticateUser, (req, res) => {
    res.status(200).json({ message: 'Access granted', user: req.user });
  });

  return app;
}

// ---- Lifecycle ------------------------------------------------------------

beforeAll(async () => {
  // Generate a real bcrypt hash for the demo user so password comparison works
  const hash = await bcrypt.hash('AdminPass123!', 10);
  authConfig.demoUsers[0].passwordHash = hash;
});

// ---- Tests ----------------------------------------------------------------

describe('User model', () => {
  test('findByUsername returns a User for a known username', () => {
    const user = User.findByUsername('admin');
    expect(user).not.toBeNull();
    expect(user.username).toBe('admin');
    expect(user.role).toBe('admin');
  });

  test('findByUsername returns null for an unknown username', () => {
    const user = User.findByUsername('unknown');
    expect(user).toBeNull();
  });

  test('findById returns a User for a known id', () => {
    const user = User.findById(1);
    expect(user).not.toBeNull();
    expect(user.id).toBe(1);
  });

  test('findById returns null for an unknown id', () => {
    const user = User.findById(999);
    expect(user).toBeNull();
  });

  test('toSafeObject does not expose passwordHash', () => {
    const user = User.findByUsername('admin');
    const safe = user.toSafeObject();
    expect(safe).not.toHaveProperty('passwordHash');
    expect(safe).toHaveProperty('id');
    expect(safe).toHaveProperty('username');
    expect(safe).toHaveProperty('role');
  });

  test('verifyPassword returns true for correct password', async () => {
    const user = User.findByUsername('admin');
    const result = await user.verifyPassword('AdminPass123!');
    expect(result).toBe(true);
  });

  test('verifyPassword returns false for incorrect password', async () => {
    const user = User.findByUsername('admin');
    const result = await user.verifyPassword('WrongPassword!');
    expect(result).toBe(false);
  });

  test('hashPassword returns a bcrypt hash', async () => {
    const hash = await User.hashPassword('SomePassword!');
    expect(hash).toMatch(/^\$2[ab]\$/);
  });

  test('hashPassword throws for empty password', async () => {
    await expect(User.hashPassword('')).rejects.toThrow('Password must not be empty.');
  });
});

describe('authenticateUser middleware', () => {
  let app;

  beforeEach(() => {
    app = buildTestApp();
  });

  test('returns 401 when no Authorization header is provided', async () => {
    const res = await request(app).get('/protected');
    expect(res.status).toBe(401);
    expect(res.body).toHaveProperty('error', 'Authentication required');
  });

  test('returns 401 for invalid credentials', async () => {
    const credentials = Buffer.from('admin:WrongPassword!').toString('base64');
    const res = await request(app)
      .get('/protected')
      .set('Authorization', `Basic ${credentials}`);
    expect(res.status).toBe(401);
    expect(res.body).toHaveProperty('error', 'Invalid credentials');
  });

  test('returns 401 for unknown username', async () => {
    const credentials = Buffer.from('nobody:AdminPass123!').toString('base64');
    const res = await request(app)
      .get('/protected')
      .set('Authorization', `Basic ${credentials}`);
    expect(res.status).toBe(401);
  });

  test('grants access with valid credentials', async () => {
    const credentials = Buffer.from('admin:AdminPass123!').toString('base64');
    const res = await request(app)
      .get('/protected')
      .set('Authorization', `Basic ${credentials}`);
    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('message', 'Access granted');
    expect(res.body.user).toHaveProperty('username', 'admin');
    expect(res.body.user).not.toHaveProperty('passwordHash');
  });
});

describe('POST /auth/login', () => {
  let app;

  beforeEach(() => {
    app = buildTestApp();
  });

  test('returns 400 when username or password is missing', async () => {
    const res = await request(app)
      .post('/auth/login')
      .send({ username: 'admin' });
    expect(res.status).toBe(400);
    expect(res.body).toHaveProperty('error', 'Bad request');
  });

  test('returns 401 for invalid credentials', async () => {
    const res = await request(app)
      .post('/auth/login')
      .send({ username: 'admin', password: 'WrongPassword!' });
    expect(res.status).toBe(401);
    expect(res.body).toHaveProperty('error', 'Invalid credentials');
  });

  test('returns 200 and user info for valid credentials', async () => {
    const res = await request(app)
      .post('/auth/login')
      .send({ username: 'admin', password: 'AdminPass123!' });
    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('message', 'Login successful.');
    expect(res.body.user).toHaveProperty('username', 'admin');
    expect(res.body.user).not.toHaveProperty('passwordHash');
  });

  test('sets a session cookie on successful login', async () => {
    const res = await request(app)
      .post('/auth/login')
      .send({ username: 'admin', password: 'AdminPass123!' });
    expect(res.status).toBe(200);
    const cookies = res.headers['set-cookie'];
    expect(cookies).toBeDefined();
    expect(cookies.some((c) => c.startsWith('cfa.sid'))).toBe(true);
  });
});

describe('POST /auth/logout', () => {
  let app;

  beforeEach(() => {
    app = buildTestApp();
  });

  test('returns 200 even when no session exists', async () => {
    const res = await request(app).post('/auth/logout');
    expect(res.status).toBe(200);
  });

  test('destroys session after login then logout', async () => {
    const agent = request.agent(app);

    // Login to establish a session
    await agent
      .post('/auth/login')
      .send({ username: 'admin', password: 'AdminPass123!' })
      .expect(200);

    // Verify session is active
    const meRes = await agent.get('/auth/me');
    expect(meRes.status).toBe(200);
    expect(meRes.body.user).toHaveProperty('username', 'admin');

    // Logout
    const logoutRes = await agent.post('/auth/logout');
    expect(logoutRes.status).toBe(200);
    expect(logoutRes.body).toHaveProperty('message', 'Logout successful.');

    // Session should be gone
    const afterLogout = await agent.get('/auth/me');
    expect(afterLogout.status).toBe(401);
  });
});

describe('GET /auth/me', () => {
  let app;

  beforeEach(() => {
    app = buildTestApp();
  });

  test('returns 401 when not authenticated', async () => {
    const res = await request(app).get('/auth/me');
    expect(res.status).toBe(401);
  });

  test('returns user info when authenticated', async () => {
    const agent = request.agent(app);

    await agent
      .post('/auth/login')
      .send({ username: 'admin', password: 'AdminPass123!' })
      .expect(200);

    const res = await agent.get('/auth/me');
    expect(res.status).toBe(200);
    expect(res.body.user).toHaveProperty('username', 'admin');
    expect(res.body.user).toHaveProperty('role', 'admin');
  });
});
